  ""entranceFees"": [
    {
      ""title"": ""Entrance - Private Vehicle"",
      ""cost"": ""$35.00"",
      ""description"": ""This pass is valid for 1-7 days and includes everyone traveling in a single vehicle for Sequoia & Kings Canyon National Parks and Hume Lake District of Sequoia National Forest/Giant Sequoia National Monument.""
    },
    {
      ""title"": ""Entrance - Per Person"",
      ""cost"": ""$20.00"",
      ""description"": ""This entry fee is for a single person traveling on foot or by bicycle. It is valid for 1-7 days in Sequoia & Kings Canyon National Parks and Hume Lake District of Sequoia National Forest/Giant Sequoia National Monument.""
    },
    {
      ""title"": ""Entrance - Motorcycle"",
      ""cost"": ""$30.00"",
      ""description"": ""Valid for 7 days. Admits up to 2 private, non-commercial motorcycles, scooters, or similar motorized vehicles with up to 4 total passengers to Sequoia & Kings Canyon National Parks and Hume Lake District of Sequoia National Forest/Giant Sequoia National Monument.""
    },
    {
      ""title"": ""Entrance - Non-commercial Groups"",
      ""cost"": ""$20.00"",
      ""description"": ""Non-commercial groups traveling in vehicles that have a capacity of up to 15 passengers pay a $35 vehicle entrance fee or use a park pass. Groups traveling in a bus or vehicle with a capacity of 16 persons or more are charged $20 per person, up to the maximums listed for commercial groups with comparable passenger capacity ($100 or $200). People 15 years old or younger, anyone with a pass that may be used for park entry, and drivers hired for transportation only are exempt from the per person fee.""
    },
    {
      ""title"": ""Commercial Entrance - Mini-bus"",
      ""cost"": ""$100.00"",
      ""description"": ""This entrance fee is for commercial tours of vehicles with a seating capacity of 16-25 people that has been packaged, priced, or sold for leisure or recreational purposes by an organization that realizes financial gain through the provision of the service. This fee is based on the seating capacity of the vehicle and not the actual number of passengers. Passenger ages or entrance passes do not affect the price.""
    },
    {
      ""title"": ""Commercial Entrance - Motor Coach"",
      ""cost"": ""$200.00"",
      ""description"": ""This entrance fee is for commercial tours of vehicles with a seating capacity of 26 or more people that has been packaged, priced, or sold for leisure or recreational purposes by an organization that realizes financial gain through the provision of the service. This fee is based on the seating capacity of the vehicle and not the actual number of passengers. Passenger ages or entrance passes do not affect the price.""
    },
    {
      ""title"": ""Commercial Entrance - Per Person"",
      ""cost"": ""$20.00"",
      ""description"": ""The per person fee for vehicles with a seating capacity of 1-6 passengers is $20, plus $25 per vehicle, with a maximum total fee of $75. This entrance fee is for commercial tours of one or more people traveling on an itinerary that has been packaged, priced, or sold for leisure or recreational purposes by an organization that realizes financial gain through the provision of the service. Passenger ages or entrance passes do not affect the price.""
    },
    {
      ""title"": ""Nonresident"",
      ""cost"": ""$100.00"",
      ""description"": ""Each non-US resident aged 16 and older visiting Sequoia & Kings Canyon National Parks must pay a $100 nonresident fee (in addition to the standard entrance fee), unless admitted with an Annual or America the Beautiful Pass. This includes nonresidents entering as part of a commercial tour group, commercial use authorization (CUA) group, or concessioner tour group.""
    }
  ],
  ""entrancePasses"": [
