        ""description"": """"
      }
    ]
  },
  ""entranceFees"": [
    {
      ""title"": ""Entrance - Private Vehicle"",
      ""cost"": ""$30.00"",
      ""description"": ""All visitors, including Non-US residents, may purchase and utilize this entrance fee. Purchasing this entrance fee allows all persons traveling in one single private, non-commercial vehicle (car/truck/van/RV/aircraft) to leave and re-enter the park as many times as they wish during the 7-day period from the date of purchase.""
    },
    {
      ""title"": ""Entrance - Motorcycle"",
      ""cost"": ""$25.00"",
      ""description"": ""All visitors, including Non-US residents, may purchase and utilize this entrance fee. Purchasing this entrance fee allows all persons traveling on 2 private, non-commercial motorcycles to leave and re-enter the park as many times as they wish during the 7-day period from the date of purchase.""
    },
    {
