      ""title"": ""Entrance - Motorcycle"",
      ""cost"": ""$15.00"",
      ""description"": ""Valid for 7 days. Admits up to 2 private, non-commercial motorcycles with up to 4 total passengers.""
    },
    {
      ""title"": ""Entrance - Per Person"",
      ""cost"": ""$10.00"",
      ""description"": ""Admits one individual when entering by foot or bicycle. Groups of up to 4 people walking in or on bicycles are capped at $20 total.\n\nIndividuals 15 years old and younger are admitted free of charge.""
    },
    {
      ""title"": ""Commercial Entrance - Sedan"",
