    {
      ""name"": ""Lands End Lookout Visitor Center"",
      ""parkCode"": ""goga"",
      ""description"": ""Facilities include visitor information and gift shop. Exhibits: Indoor exhibits and videos on the natural and cultural history of the Lands End area, Sutro Baths and Sutro Heights. Outdoor 3-D model of Lands End area."",
      ""url"": ""http://www.nps.gov/goga/planyourvisit/landsend.htm"",
      ""directionsInfo"": ""Located at the Merrie Way parking area just east of the Cliff House and west of the cross streets of Point Lobos Avenue (very west end of Geary Blvd.), and El Camino del Mar in San Francisco, California."",
      ""directionsUrl"": ""http://www.parksconservancy.org/visit/park-sites/lands-end.html"",
      ""location"": {
        ""latitude"": ""37.7797300961"",
        ""longitude"": ""-122.511611527"",
        ""address"": {
          ""line1"": ""680 Point Lobos Ave"",
          ""line2"": """",
          ""city"": ""San Francisco"",
          ""stateCode"": ""CA"",
          ""postalCode"": ""94121""
        }
      },
      ""operatingHours"": [
        {
          ""name"": ""Lands End Lookout Visitor Center"",
          ""description"": ""Lands End Lookout is open 7 days a week 9am to 5pm. \n\nAt the northwestern corner of San Francisco, there is wild and windy trail with stunning views at every turn... Lands End's trails winds their way around rocky cliffs above the ocean, moving through shady stands of cypress and eucalyptus and emerging on to spectacular views of the shore, headlands, and Golden Gate. A trip down the trail is also a journey through the history of Lands End, offering glimpses of the past at every turn."",
          ""standardHours"": [
            ""Wednesday: 9:00AM - 5:00PM"",
            ""Monday: 9:00AM - 5:00PM"",
            ""Thursday: 9:00AM - 5:00PM"",
            ""Sunday: 9:00AM - 5:00PM"",
            ""Tuesday: 9:00AM - 5:00PM"",
            ""Friday: 9:00AM - 5:00PM"",
            ""Saturday: 9:00AM - 5:00PM""
          ]
        }
      ],
      ""contacts"": {
        ""phoneNumbers"": [
          {
            ""type"": ""Voice"",
            ""number"": ""4154265240"",
            ""extension"": """",
            ""description"": """"
          }
        ],
        ""emailAddresses"": [
          {
            ""address"": ""goga_socialmedia_goga@nps.gov"",
            ""description"": """"
          }
        ]
      }
    },
    {
      ""name"": ""Muir Woods National Monument Visitor Center"",
      ""parkCode"": ""goga"",
      ""description"": ""Please visit gomuirwoods.com for reservations. Starting Saturday, May 28 our new operating hours will be 8:00 a.m. - 6:00 p.m. The Muir Woods Visitor Center is open 8:00 am to 30 minutes before the park closes."",
      ""url"": ""https://www.nps.gov/muwo/index.htm"",
      ""directionsInfo"": ""From San Francisco Muir Woods is located 11 miles north of the Golden Gate Bridge Take Highway 101 North Take the Mill Valley/Highway 1/ Stinson Beach Exit Follow the signs to Highway 1 Follow the signs to Muir Woods From the East Bay Take the Highway 580/Richmond/San Rafael Bridge West Take Highway 101 South Take the Stinson Beach/Mill Valley Exit Follow the signs to Highway 1 Follow the signs to Muir Woods Vehicles over 35 feet long are prohibited. There are no RV parking facilities."",
      ""directionsUrl"": ""http://www.nps.gov/muwo/planyourvisit/directions.htm"",
      ""location"": {
        ""latitude"": ""37.8928477998"",
        ""longitude"": ""-122.572464989"",
        ""address"": {
          ""line1"": ""Muir Woods Visitor Center"",
