      ""operatingHours"": [
        {
          ""name"": ""Muir Woods National Monument Visitor Center"",
          ""description"": ""Muir Woods National Monument is open daily with hours that vary throughout the year. \n\nStarting Saturday, May 28 our new operating hours will be 8:00 a.m. - 6:00 p.m.\n\nThe Muir Woods Visitor Center is open 8:00 am to 30 minutes before the park closes."",
          ""standardHours"": [
