          ""briefTitle"": ""Exogenous Testosterone Plus Dutasteride for the Treatment of Castrate Metastatic Prostate Cancer"",
          ""officialTitle"": ""Phase II Trial of Exogenous Testosterone Plus Dutasteride for the Treatment of Castrate Metastatic Prostate Cancer""
        },
        ""statusModule"": {
          ""statusVerifiedDate"": ""2015-10"",
          ""overallStatus"": ""COMPLETED"",
          ""expandedAccessInfo"": {
            ""hasExpandedAccess"": false
