        },
        ""sponsorCollaboratorsModule"": {
          ""responsibleParty"": {
            ""type"": ""SPONSOR""
          },
          ""leadSponsor"": {
            ""name"": ""Memorial Sloan Kettering Cancer Center"",
            ""class"": ""OTHER""
          },
          ""collaborators"": [
